#include <iostream>
#include <queue>
using namespace std;
queue<int> Q;
bool a[1005];
int main()
{
    int m,n,count=0;
    cin>>m>>n;
    for(int i=1;i<=n;i++)
    {
        int t;
        cin>>t;
        if(a[t]==false)
        {
            count++;
            if(Q.size()==m)
            {
                a[Q.front()]=false;
                Q.pop();
            }
            Q.push(t);
            a[t]=true;
        }
    }
    cout<<count;
    return 0;
}
